  5→export interface WikiArticle {
  6→    title: string;
  7→    displaytitle: string;
  8→    extract: string;
  9→    pageid: number;
 10→    url: string;
 11→    thumbnail: {
 12→        source: string;
 13→        width: number;
 14→        height: number;
 15→    };
 16→}
